var p = msg.payload;

// Camera controls
var controls = {};

// Exposure
controls.AeEnable = p.exposure_auto !== false;
if (!controls.AeEnable) {
    controls.ExposureTime = parseInt(p.exposure_us) || 20000;
}

// Gain (independent from AE — fix: don't override AeEnable)
if (p.gain_auto === false) {
    controls.AnalogueGain = parseFloat(p.gain) || 1.0;
}

// EV compensation (useful with AeEnable=true)
if (p.ev !== undefined && p.ev !== null) {
    controls.ExposureValue = parseFloat(p.ev) || 0.0;
}

// White balance
controls.AwbEnable = p.wb_auto !== false;
if (!controls.AwbEnable) {
    controls.ColourGains = [parseFloat(p.wb_r) || 1.5, parseFloat(p.wb_b) || 1.8];
}

// AWB mode preset
var awbModes = {Auto:0, Tungsten:1, Fluorescent:2, Indoor:3, Daylight:4, Cloudy:5, Custom:6};
if (p.awb_mode && awbModes[p.awb_mode] !== undefined) {
    controls.AwbMode = awbModes[p.awb_mode];
}

// Metering mode
var meteringModes = {CentreWeighted:0, Spot:1, Matrix:2, Custom:3};
if (p.metering_mode && meteringModes[p.metering_mode] !== undefined) {
    controls.AeMeteringMode = meteringModes[p.metering_mode];
}

// Noise reduction (Off recommended for scientific imaging)
var nrModes = {Off:0, Fast:1, HighQuality:2};
if (p.noise_reduction && nrModes[p.noise_reduction] !== undefined) {
    controls.NoiseReductionMode = nrModes[p.noise_reduction];
}

// Camera settings (resolution/framerate)
var settings = {};
if (p.resolution) settings.resolution = p.resolution;
if (p.framerate) settings.framerate = p.framerate;

msg.controls = controls;
msg.settings = settings;
msg.payload = controls;
msg.headers = {'Content-Type': 'application/json'};
return msg;

